    file-write operator (> redirect) payloads.
    Returns dict with 'vulnerable', 'output', 'separator'."""
    TAG = ''.join(random.choice(string.ascii_uppercase) for _ in range(6))
    test_cmd = 'echo ' + TAG
    SEPARATORS = [';', '|', '&&', '%0a']
    FILE_WRITE_OPS = [' > ', ' >> ']
