                if TAG in body:
                    return {'vulnerable': True, 'output': body, 'separator': sep, 'write_op': write_op.strip(), 'output_path': writable_path}
            except Exception:
                continue
    return {'vulnerable': False, 'output': None, 'separator': None}

def file_inject_command(url, param, separator, write_op, writable_path, readable_url, command):
