import urllib.parse
import string

def encode_payload(payload, level=1):
    """Multi-level URL encoding for injection payload filter bypass.
    Level 1: Standard percent-encoding (%HH).
    Level 2: Double-encoding (encode the percent sign itself -> %25HH).
    Level 3: IIS Unicode encoding (%u00HH format).
    Level 4: Overlong UTF-8 encoding for path traversal bypass.
    Preserves already-encoded sequences at level 1."""
    if level == 1:
        return _encode_level1(payload)
    elif level == 2:
        return _encode_level2(payload)
    elif level == 3:
        return _encode_unicode(payload)
    elif level == 4:
        return _encode_overlong(payload)
    else:
        raise ValueError('Encoding level must be 1-4')

def _encode_level1(payload):
    """Standard URL encoding. Preserves existing %XX sequences."""
    result = []
    i = 0
    while i < len(payload):
        if (payload[i] == '%' and i + 2 < len(payload)
                and payload[i+1] in string.hexdigits
                and payload[i+2] in string.hexdigits):
            result.append(payload[i:i+3])
            i += 3
        else:
            result.append('%%%02X' % ord(payload[i]))
            i += 1
    return ''.join(result)

def _encode_level2(payload):
    """Double URL encoding: %XX -> %25XX. WAFs that decode once pass it through."""
    first_pass = _encode_level1(payload)
    result = []
    i = 0
    while i < len(first_pass):
        if first_pass[i] == '%':
            result.append('%25')
            i += 1
        else:
            result.append('%%%02X' % ord(first_pass[i]))
            i += 1
    return ''.join(result)

def _encode_unicode(payload):
    """IIS Unicode %u00XX encoding. Works on IIS servers that parse Unicode escapes."""
    return ''.join('%%u00%02X' % ord(c) for c in payload)

def _encode_overlong(payload):
    """Overlong UTF-8 encoding for slash/dot traversal bypass.
    '/' (0x2F) -> %C0%AF, '.' (0x2E) -> %C0%AE. Other chars use standard encoding."""
    OVERLONG = {
        '/': '%C0%AF',
        '.': '%C0%AE',
        '\\': '%C1%9C',
    }
    result = []
    for c in payload:
        if c in OVERLONG:
            result.append(OVERLONG[c])
        else:
            result.append('%%%02X' % ord(c))
    return ''.join(result)

def encode_selective(payload, chars_to_encode, level=1):
    """Encode only specific characters in the payload. Useful for
    bypassing filters that block specific chars (;, |, &, space)."""
    result = []
    for c in payload:
        if c in chars_to_encode:
            if level == 1:
                result.append('%%%02X' % ord(c))
            elif level == 2:
                result.append('%%25%02X' % ord(c))
            elif level == 3:
                result.append('%%u00%02X' % ord(c))
            else:
                result.append(c)
        else:
            result.append(c)
    return ''.join(result)

def decode_multi(payload, levels=1):
    """Iteratively URL-decode a payload N times (reverse of multi-level encoding)."""
    result = payload
    for _ in range(levels):
        result = urllib.parse.unquote(result)
    return result
